                                Giriş Yap
                            </button>
                        )}
                        </div>

                        <div className="h-6 w-px bg-[var(--border-color)] mx-1"></div>
                        <button onClick={() => setOpenModal('settings')} className={headerIconBtnClass}><i className="fa-solid fa-gear fa-lg"></i></button>
