    return (
        <div className="relative w-full h-full min-h-[800px] bg-white text-black">
            {layout.filter(l => l.isVisible).map((item: any) => (
                <div 
                    key={item.instanceId} 
                    className="absolute" 
                    style={{ 
                        left: item.style.x, 
                        top: item.style.y, 
                        width: item.style.w, 
                        height: item.style.h, 
