import { db } from './firebaseClient';
import * as firestore from "firebase/firestore";
import { SavedWorksheet, SingleWorksheetData, ActivityType, StyleSettings, StudentProfile, CollectionItem, WorkbookSettings } from '../types';

const { collection, addDoc, query, where, getDocs, doc, updateDoc, increment, deleteDoc, getDoc } = firestore;

const serializeData = (data: any): string => {
    try {
        return JSON.stringify(data);
    } catch (e) {
        console.error("Serialization error", e);
        return "[]";
    }
};

const deserializeData = (data: any): SingleWorksheetData[] => {
    if (!data) return [];

    let parsed: any = [];
    if (typeof data === 'string') {
        try {
            parsed = JSON.parse(data);
        } catch (e) {
            console.error("Deserialization error", e);
            return [];
        }
    } else {
        parsed = data;
    }

    if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
        return [parsed];
    }

    return Array.isArray(parsed) ? parsed : [];
};

const mapDbToWorksheet = (docData: any, id: string): SavedWorksheet => ({
    id: id,
    userId: docData.userId,
    studentId: docData.studentId,
    name: docData.name,
    activityType: docData.activityType as ActivityType,
    worksheetData: deserializeData(docData.worksheetData),
    createdAt: docData.createdAt,
    icon: docData.icon || 'fa-solid fa-file',
    category: docData.category || { id: 'uncategorized', title: 'Kategorisiz' },
    sharedBy: docData.sharedBy,
    sharedByName: docData.sharedByName,
    sharedWith: docData.sharedWith,
    styleSettings: docData.styleSettings,
    studentProfile: docData.studentProfile,
    workbookItems: docData.workbookItems ? deserializeData(docData.workbookItems) : undefined,
    workbookSettings: docData.workbookSettings
});

export const worksheetService = {
    saveWorksheet: async (
        userId: string, 
        name: string, 
        activityType: ActivityType, 
        data: SingleWorksheetData[], 
        icon: string,
        category: { id: string, title: string },
        styleSettings?: StyleSettings,
        studentProfile?: StudentProfile,
        studentId?: string
    ): Promise<SavedWorksheet> => {
        try {
            const payload: any = {
                userId,
                studentId: studentId || null,
                name: name || 'Adsız Etkinlik',
                activityType,
                worksheetData: serializeData(data),
                icon: icon || 'fa-solid fa-file',
                category: category || { id: 'uncategorized', title: 'Kategorisiz' },
                createdAt: new Date().toISOString(),
            };

            if (styleSettings) payload.styleSettings = styleSettings;
            if (studentProfile) payload.studentProfile = studentProfile;

            const docRef = await addDoc(collection(db, "saved_worksheets"), payload);
            const userRef = doc(db, "users", userId);
            updateDoc(userRef, { worksheetCount: increment(1) }).catch(console.warn);

            return {
                ...mapDbToWorksheet(payload, docRef.id),
                worksheetData: data 
            };
        } catch (error) {
            console.error("Error saving worksheet:", error);
            throw error;
        }
    },

    getUserWorksheets: async (userId: string, page: number, pageSize: number): Promise<{ items: SavedWorksheet[], count: number | null }> => {
        try {
            const q = query(collection(db, "saved_worksheets"), where("userId", "==", userId));
            const querySnapshot = await getDocs(q);
            const items: SavedWorksheet[] = [];
            querySnapshot.forEach((doc) => {
                const data = doc.data() as any;
                if (!data.sharedWith) items.push(mapDbToWorksheet(data, doc.id));
            });
            items.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
            return { items, count: items.length };
        } catch (error) {
            return { items: [], count: 0 };
        }
    },

    getWorksheetsByStudent: async (studentId: string): Promise<SavedWorksheet[]> => {
        try {
            const q = query(collection(db, "saved_worksheets"), where("studentId", "==", studentId));
            const querySnapshot = await getDocs(q);
            const items: SavedWorksheet[] = [];
            querySnapshot.forEach((doc) => {
                items.push(mapDbToWorksheet(doc.data(), doc.id));
            });
            items.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
            return items;
        } catch (error) {
            console.error("Error fetching student worksheets:", error);
            return [];
        }
    },

    getSharedWithMe: async (userId: string, page: number, pageSize: number): Promise<{ items: SavedWorksheet[], count: number | null }> => {
        try {
            const q = query(
                collection(db, "saved_worksheets"), 
                where("sharedWith", "==", userId)
            );
            const querySnapshot = await getDocs(q);
            const items: SavedWorksheet[] = [];
            querySnapshot.forEach((doc) => {
                items.push(mapDbToWorksheet(doc.data(), doc.id));
            });
            items.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
            return { items, count: items.length };
        } catch (error) {
            return { items: [], count: 0 };
        }
    },

    shareWorksheet: async (worksheet: any, senderId: string, senderName: string, receiverId: string): Promise<void> => {
        const payload = {
            ...worksheet,
            userId: senderId,
            sharedBy: senderId,
            sharedByName: senderName,
            sharedWith: receiverId,
            createdAt: new Date().toISOString()
        };

        if (Array.isArray(payload.worksheetData)) {
            payload.worksheetData = serializeData(payload.worksheetData);
        }
        if (Array.isArray(payload.workbookItems)) {
            payload.workbookItems = serializeData(payload.workbookItems);
        }

        await addDoc(collection(db, "saved_worksheets"), payload);
    },

    deleteWorksheet: async (id: string) => {
        await deleteDoc(doc(db, "saved_worksheets", id));
    },

    saveWorkbook: async (userId: string, settings: WorkbookSettings, items: CollectionItem[], studentId?: string): Promise<SavedWorksheet> => {
        try {
            const payload: any = {
                userId,
                studentId: studentId || null,
                name: settings.title || 'Adsız Kitapçık',
                activityType: ActivityType.WORKBOOK,
                worksheetData: "[]",
                icon: 'fa-solid fa-book-journal-whills',
                category: { id: 'workbook', title: 'Çalışma Kitapçığı' },
                createdAt: new Date().toISOString(),
                workbookSettings: settings,
                workbookItems: serializeData(items)
            };
            const docRef = await addDoc(collection(db, "saved_worksheets"), payload);
            return mapDbToWorksheet(payload, docRef.id);
        } catch (error) {
            throw error;
        }
    }
};

import { GoogleGenAI } from "@google/genai";

const DEFAULT_MODEL = 'gemini-3-flash-preview';

const tryRepairJson = (jsonStr: string): any => {
    let cleaned = jsonStr.replace(/```json\s*/gi, '').replace(/```\s*$/g, '').trim();

    try {
        return JSON.parse(cleaned);
    } catch (e) {
        console.warn("Primary JSON Parse failed, attempting extreme repair...");

        // 1. Remove repetitive patterns that often break JSON (Hallucination fix)
        const loopMatch = cleaned.match(/(.{50,})\1{2,}/g);
        if (loopMatch) {
            cleaned = cleaned.replace(/(.{50,})\1{5,}/g, '$1'); 
        }

        // 2. Fix missing commas between elements
        cleaned = cleaned.replace(/}\s*{/g, '},{').replace(/]\s*\[/g, '],[');

        // 3. Balance quotes
        let quoteCount = 0;
        for (let i = 0; i < cleaned.length; i++) {
            if (cleaned[i] === '"' && (i === 0 || cleaned[i-1] !== '\\')) quoteCount++;
        }
        if (quoteCount % 2 !== 0) cleaned += '"';

        // 4. Force balance brackets/braces
        let repaired = cleaned;
        const openBraces = (repaired.match(/{/g) || []).length;
        const closeBraces = (repaired.match(/}/g) || []).length;
        const openBrackets = (repaired.match(/\[/g) || []).length;
        const closeBrackets = (repaired.match(/\]/g) || []).length;

        for (let i = 0; i < (openBraces - closeBraces); i++) repaired += '}';
        for (let i = 0; i < (openBrackets - closeBrackets); i++) repaired += ']';

        try {
            return JSON.parse(repaired);
        } catch (e2) {
             const lastGoodIndex = Math.max(repaired.lastIndexOf('}'), repaired.lastIndexOf(']'));
             if (lastGoodIndex > 0) {
                 const truncated = repaired.substring(0, lastGoodIndex + 1);
                 try { return JSON.parse(truncated); } catch (e3) {}
             }
             throw new Error("Yapay zeka yanıtı onarılamayacak kadar bozuk.");
        }
    }
};

const SYSTEM_INSTRUCTION = `
Sen, Bursa Disleksi AI platformunun yapay zeka motorusun.
Disleksi, Diskalkuli ve DEHB için materyal üretirsin.
Kural: Sadece JSON döndür. Multimodal yeteneklerini (görsel analiz ve zengin metin üretimi) en üst seviyede kullan.
Döngüsel metinlerden (aynı cümleyi tekrar etmek) KESİNLİKLE kaçın.
`;

const generateDirectly = async (params: { 
    prompt: string, 
    schema: any, 
    model?: string, 
    image?: string, 
    mimeType?: string,
    useSearch?: boolean 
}) => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) throw new Error("API Anahtarı eksik.");

    const ai = new GoogleGenAI({ apiKey });
    const modelName = params.model || DEFAULT_MODEL;

    let parts: any[] = [];
    if (params.image) {
        parts.push({ 
            inlineData: { 
                mimeType: params.mimeType || 'image/jpeg', 
                data: params.image.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, "") 
            } 
        });
    }
    parts.push({ text: params.prompt });

    const config: any = {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: params.schema,
        temperature: 0.2,
    };

    if (params.useSearch) config.tools = [{ googleSearch: {} }];

    const response = await ai.models.generateContent({
        model: modelName,
        contents: [{ role: 'user', parts }],
        config: config
    });

    if (response.text) return tryRepairJson(response.text);
    throw new Error("Boş yanıt alındı.");
};

export const generateWithSchema = async (prompt: string, schema: any, model?: string, useSearch?: boolean) => {
    const targetModel = model || DEFAULT_MODEL;
    try {
        const response = await fetch('/api/generate', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ prompt, schema, model: targetModel, useSearch: useSearch || false }),
        });
        if (!response.ok) return await generateDirectly({ prompt, schema, model: targetModel, useSearch });
        const fullText = await response.text();
        return tryRepairJson(fullText);
    } catch (error: any) {
        return await generateDirectly({ prompt, schema, model: targetModel, useSearch });
    }
};

export const analyzeImage = async (base64Image: string, prompt: string, schema: any, model?: string) => {
    const targetModel = model || DEFAULT_MODEL;
    try {
        const cleanBase64 = base64Image.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, "");
        const response = await fetch('/api/generate', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ prompt, schema, image: cleanBase64, mimeType: 'image/jpeg', model: targetModel }),
        });
        if (!response.ok) return await generateDirectly({ prompt, schema, image: base64Image, model: targetModel });
        const fullText = await response.text();
        return tryRepairJson(fullText);
    } catch (error: any) {
        return await generateDirectly({ prompt, schema, image: base64Image, model: targetModel });
    }
};

import type { VercelRequest, VercelResponse } from '@vercel/node';
import { GoogleGenAI, HarmCategory, HarmBlockThreshold } from "@google/genai";

const DEFAULT_MODEL = "gemini-3-flash-preview";

const SYSTEM_INSTRUCTION = `
Sen, Bursa Disleksi AI platformunun yapay zeka motorusun.
Görevin: Disleksi, Diskalkuli ve DEHB tanısı almış veya risk grubundaki çocuklar için bilimsel temelli, hatasız ve JSON formatında eğitim materyali üretmek.
Multimodal yeteneklerini (görsel analiz ve zengin metin üretimi) en üst seviyede kullan.
Yanıtın SADECE geçerli bir JSON olmalıdır. Başka hiçbir açıklama yapma.
DİKKAT: Cümleleri veya objeleri sonsuz döngüde tekrar etme!
`;

export default async function handler(req: VercelRequest, res: VercelResponse) {
    res.setHeader('Access-Control-Allow-Origin', '*');
    res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');
    res.setHeader('Access-Control-Allow-Headers', 'Content-Type');

    if (req.method === 'OPTIONS') return res.status(200).end();
    if (req.method !== 'POST') return res.status(405).json({ error: `Method ${req.method} Not Allowed` });

    try {
        const { prompt, schema, image, mimeType, useSearch, model } = req.body;
        const apiKey = process.env.API_KEY;
        if (!apiKey) return res.status(500).json({ error: 'API anahtarı eksik.' });

        const ai = new GoogleGenAI({ apiKey });
        const selectedModel = model || DEFAULT_MODEL;

        const generationConfig = {
            systemInstruction: SYSTEM_INSTRUCTION,
            responseMimeType: "application/json",
            responseSchema: schema,
            temperature: 0.2, 
            topP: 0.8,
            topK: 40,
            safetySettings: [
                { category: HarmCategory.HARM_CATEGORY_HARASSMENT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
                { category: HarmCategory.HARM_CATEGORY_HATE_SPEECH, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
                { category: HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
                { category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
            ]
        };

        if (useSearch) (generationConfig as any).tools = [{ googleSearch: {} }];

        let parts: any[] = [];
        if (image) {
            parts.push({ inlineData: { mimeType: mimeType || 'image/jpeg', data: image.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, "") } });
        }
        parts.push({ text: prompt });

        const result = await ai.models.generateContent({
            model: selectedModel,
            contents: [{ role: 'user', parts }],
            config: generationConfig,
        });

        if (result.text) {
            res.setHeader('Content-Type', 'application/json; charset=utf-8');
            return res.status(200).send(result.text);
        }
        throw new Error("AI yanıt üretemedi.");
    } catch (error: any) {
        console.error("API Handler Error:", error);
        return res.status(500).json({ error: error.message });
    }
}

